case class Product(id: Int, name: String, price: Double, category: String)

@Singleton
class ProductController @Inject()(val controllerComponents: ControllerComponents)(implicit ec: ExecutionContext) extends BaseController {
  
  def searchProducts() = Action.async { implicit request =>
    val nameFilter = request.queryString.get("name").flatMap(_.headOption)
    val categoryFilter = request.queryString.get("category").flatMap(_.headOption)
    val minPrice = request.queryString.get("minPrice").flatMap(_.headOption.flatMap(_.toDoubleOption))
