  private def buildWhereClause(name: Option[String], category: Option[String], minPrice: Option[Double], maxPrice: Option[Double]): SqlNode = {
    val conditions = List(
      name.map(name => sql"LOWER(name) LIKE LOWER(${name})"),
      category.map(category => sql"category = ${category}"),
      minPrice.map(price => sql"price >= ${price}"),
